balapaCop = function(title, theFontColor) {
  var title, theFontColor;

  var style =
    "@import url(https://fonts.googleapis.com/css?family=Quicksand:400,700);.copyright{position:fixed;right:15px;bottom:15px;font-family:Quicksand}.copyright span{line-height:30px;color:" +
    theFontColor +
    ";margin-right:7.5px;float:left}.copyright span a{font-weight:400;text-decoration:none;color:#ea4c89}.copyright .balapa{width:24px;height:24px;display:block;background:url(https://s3-us-west-2.amazonaws.com/s.cdpn.io/111167/balapa.jpg);background-size:cover;border-radius:50%;border:3px solid rgba(0,0,0,.25);float:right}";

  var tag =
    "<span>" +
    title +
    " by</span><a class='balapa' href='http://balap.us' target='_blank'></a>";

  var genTag, genStyle;

  genStyle = document.createElement("style");
  genStyle.innerHTML = style;

  genTag = document.createElement("div");
  genTag.className = "copyright";
  genTag.innerHTML = tag;

  document.body.appendChild(genStyle);
  document.body.appendChild(genTag);
};

//

function init() {
  var canvas = document.getElementById("canvas-elastic-fire"),
    ctx = canvas.getContext("2d");

  var w = (canvas.width = window.innerWidth * 2);
  var h = (canvas.height = window.innerHeight * 2);

  var numParticles = 50,
    particles = [],
    radius = 12,
    speed = 0.1;

  function randomize(min, max) {
    return Math.round(Math.random() * (max - min) + min);
  }

  var pos = {
    x: w / 2,
    y: h / 2
  };

  var colors = ["#e67e22", "#e74c3c", "blue"];

  // clone object pos
  var accel = JSON.parse(JSON.stringify(pos));

  document.body.addEventListener("mousemove", function(e) {
    pos.x = e.clientX;
    pos.y = e.clientY;
  });

  for (var i = 0; i < numParticles; i++) {
    particles.push(new generate());
  }

  function generate() {
    this.x = pos.x;
    this.y = pos.y;
    this.radius = randomize(3, 6);
    this.color = colors[Math.floor(Math.random() * colors.length)];
    this.vx = randomize(-2, 2);
    this.vy = randomize(5, 10);
    this.life = randomize(20, 30);
  }

  render();

  function render() {
    // console.log("render: ");
    ctx.clearRect(0, 0, w, h);

    accel.x += (pos.x - accel.x) * 0.15;
    accel.y += (pos.y - accel.y) * 0.15;

    ctx.beginPath();
    ctx.fillStyle = "#f1c40f";
    ctx.arc(accel.x, accel.y, radius, 0, Math.PI * 2, false);
    ctx.fill();
    ctx.globalCompositeOperation = "xor";

    for (var j = 0; j < particles.length; j++) {
      var p = particles[j];

      ctx.beginPath();
      ctx.fillStyle = p.color;
      ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2, false);
      ctx.fill();

      p.x += p.vx;
      p.y -= p.vy;

      p.radius -= 0.075;
      p.life--;

      if (p.life < 0 || p.radius < 0) {
        particles[j] = new generate();
      }
    }

    requestAnimationFrame(render);
  }
}

